                                                                                                                                                                                                                                                                                                                                                      //motor de busqueda//
                                                                                                                                                                                                                                                                                                                                                      function cleartext(text){
                                                                                                                                                                                                                                                                                                                                                        return text .trim()
                                                                                                                                                                                                                                                                                                                                                                      .toLowerCase()
                                                                                                                                                                                                                                                                                                                                                                                    .normalize("NFD")
                                                                                                                                                                                                                                                                                                                                                                                                  .replace(/[\u0300-\u036f]/g, "");
                                                                                                                                                                                                                                                                                                                                                                                                  }

                                                                                                                                                                                                                                                                                                                                                                                                  function buscador(data){
                                                                                                                                                                                                                                                                                                                                                                                                    const entrada = cleartext(data);
                                                                                                                                                                                                                                                                                                                                                                                                      let resultado = List.filter(f=>{
                                                                                                                                                                                                                                                                                                                                                                                                          let titulo = cleartext(f.titulo);
                                                                                                                                                                                                                                                                                                                                                                                                              let lang = cleartext(f.lang);
                                                                                                                                                                                                                                                                                                                                                                                                                  return titulo.includes(entrada) && lang.includes(idioma);;
                                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                                      return resultado;
                                                                                                                                                                                                                                                                                                                                                                                                                      }

